// Genius XOR trick - no extra space
function missingNumberXOR(arr, n) {
  let missing = n * (n + 1) / 2;
  let xor = 0;
  for (let i = 1; i <= n; i++) xor ^= i;
  for (const num of arr) xor ^= num;
  return xor;
}

function missingNumberSum(arr, n) {
  const expected = n * (n + 1) / 2;
  return expected - arr.reduce((sum, num) => sum + num, 0);
}

function missingNumberSet(arr, n) {
  const set = new Set(arr);
  for (let i = 1; i <= n; i++) {
    if (!set.has(i)) return i;
  }
}
